<?php require_once __DIR__.'/../../../backend/includes/helpers.php'; function lev($k,$l=null,$d=''){return e((string)($l[$k]??$d));} ?>
<div class="bg-white border rounded p-3"><div class="row"><div class="col-md-6 mb-3"><label class="form-label">Client *</label><select class="form-select" name="client_id" required><option value="">Selectionner</option><?php foreach($clients as $c): ?><option value="<?php echo e((string)$c['id']); ?>" <?php echo lev('client_id',$letter??null)==$c['id']?'selected':''; ?>><?php echo e($c['company_name']); ?></option><?php endforeach; ?></select></div><div class="col-md-6 mb-3"><label class="form-label">Mission</label><select class="form-select" name="mission_id"><option value="">Aucune</option><?php foreach($missions as $m): ?><option value="<?php echo e((string)$m['id']); ?>" <?php echo lev('mission_id',$letter??null)==$m['id']?'selected':''; ?>><?php echo e($m['title']); ?></option><?php endforeach; ?></select></div><div class="col-12 mb-3"><label class="form-label">Titre *</label><input class="form-control" name="title" required value="<?php echo lev('title',$letter??null); ?>"></div><div class="col-12 mb-3"><label class="form-label">Texte *</label><textarea class="form-control" name="content" rows="10" required><?php echo e($content??''); ?></textarea></div></div></div>
